const WebSocket = require('ws');
const fs = require('fs');

// Test configuration
const SERVER_URL = 'ws://localhost:3001/ws/bridge';

// Read token from file (generated by test-pairing.sh)
let TEST_TOKEN;
try {
  TEST_TOKEN = fs.readFileSync('/tmp/pairing-token.txt', 'utf8').trim();
  console.log('📋 Using pairing token:', TEST_TOKEN.substring(0, 20) + '...');
} catch (err) {
  console.error('❌ Could not read pairing token from /tmp/pairing-token.txt');
  console.error('   Run ./test-pairing.sh first to generate a token');
  process.exit(1);
}

console.log('🧪 WebSocket Bridge Test Client');
console.log('================================\n');

// Create WebSocket connection
const ws = new WebSocket(`${SERVER_URL}?token=${TEST_TOKEN}`);

ws.on('open', () => {
  console.log('✅ Connected to server');
  
  // Send handshake
  const handshake = {
    type: 'handshake',
    nodeKey: 'test-node-' + Date.now(),
    agents: ['agent_test_123', 'agent_test_456'],
    platform: 'linux'
  };
  
  console.log('📤 Sending handshake:', handshake);
  ws.send(JSON.stringify(handshake));
});

ws.on('message', (data) => {
  const message = JSON.parse(data.toString());
  console.log('📨 Received:', message);
  
  // Handle different message types
  switch (message.type) {
    case 'auth_ok':
      console.log('✅ Authentication successful');
      break;
      
    case 'handshake_complete':
      console.log('✅ Handshake complete! Node ID:', message.nodeId);
      console.log('\n🎉 Test successful! Press Ctrl+C to exit.');
      break;
      
    case 'ping':
      console.log('💓 Ping received, sending pong...');
      ws.send(JSON.stringify({ type: 'pong' }));
      break;
      
    case 'execute':
      console.log('🚀 Execution request:', {
        sessionId: message.sessionId,
        agentId: message.agentId,
        instruction: message.instruction
      });
      // Simulate response
      setTimeout(() => {
        ws.send(JSON.stringify({
          type: 'result',
          sessionId: message.sessionId,
          content: 'Task completed successfully!',
          done: true
        }));
      }, 1000);
      break;
      
    case 'error':
      console.log('❌ Error:', message.message);
      break;
      
    default:
      console.log('⚠️ Unknown message type:', message.type);
  }
});

ws.on('error', (error) => {
  console.error('❌ WebSocket error:', error.message);
});

ws.on('close', (code, reason) => {
  console.log(`🔌 Connection closed (code: ${code}, reason: ${reason || 'none'})`);
  process.exit(0);
});

// Handle Ctrl+C
process.on('SIGINT', () => {
  console.log('\n\n👋 Closing connection...');
  ws.close(1000, 'Client disconnect');
});
